"function startDrawing(e) {
    if (!isDrawingMode || e.button !== 0) return; // رسم باليسار فقط
    isPainting = true;
    const pos = getCanvasMousePos(e);
    lastX = pos.x;
    lastY = pos.y;

    // حفظ اللقطة الحالية قبل الرسم الجديد للتراجع
    const ctx = drawingCanvas.getContext('2d');
    if (drawingHistory.length >= 25) {
        drawingHistory.shift(); // حد أقصى للذاكرة
    }
    drawingHistory.push(ctx.getImageData(0, 0, drawingCanvas.width, drawingCanvas.height));
}

function draw(e) {
    if (!isPainting || !isDrawingMode) return;
    const ctx = drawingCanvas.getContext('2d');
    const pos = getCanvasMousePos(e);

    ctx.beginPath();
    ctx.moveTo(lastX, lastY);
    ctx.lineTo(pos.x, pos.y);

    ctx.strokeStyle = brushColor;
    ctx.lineWidth = brushSize;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.globalAlpha = brushOpacity / 100;

    ctx.stroke();

    lastX = pos.x;
    lastY = pos.y;
}

function stopDrawing() {
    if (isPainting) {
        isPainting = false;
        hasUnsavedDrawings = true;
        updateDrawingSaveState();
    }
}

